+    #[test]
+    fn test_json_each_vtab_cursor_scan() {
+        let cx = Cx::new();
+        let vtab = JsonEachVtab::connect(&cx, &[]).unwrap();
+        let mut cursor = vtab.open().unwrap();
+        cursor
